    ('ERA III 1, 127 (2)', 'ERA II 21, 155/6', 'ERA, Fon. 258 a', NULL, 'XII 358 / 364', 1, 1, 1, NULL, '<Helisalvestus: Selge, lõpuosas mingi kahjustus. Märgitud: (Fon. N 1 a)>
    <Kontrollitud: T. O. Ilmselt on välitöödel tehtud noodistust hiljem fonogrammi järgi täpsustatud. Lisasin heli viite. Teksti juures on vanad fonogrammi numbrid. Koguja on teksti jaganud a ja b osaks, digiteerija on jaganud ka fonogrammi.>', 1, 4411),
    ('ERA III 1, 127 (2)', 'ERA II 21, 156/8', 'ERA, Fon. 258 a1', NULL, 'XV 389', 1, 1, 1, NULL, '<Helisalvestus: Selge, algul vaikset juttu (13 sek). Märgitud: Fon. N 1 b.>
    <Kontrollitud: T. O. Ilmselt on välitööde noodistust hiljem fonogrammi järgi täpsustatud. Parandasin teksti viite: oli ERA II 155/8 (3), lisasin heli viite. Teksti juures on vanad fonogrammi numbrid ja ilmsalt pärast fonogrammi kuulamist lisatud märkusi, sealhulgas mõned noodid.>', 1, 3860),
    ('ERA III 1, 129 (5)', 'ERA II 21, 167/8 (8)', 'ERA, Fon. 261 a', NULL, 'XII 429', 1, 1, 1, NULL, '<Helisalvestus: Selge, noodist pikem>
    <Kontrollitud: T. O. Parandasin heli viite (oli Fon. 262 b.), täpsustasin laululiiki ja -tüüpi kuulamise põhjal. Noodi ja teksti juures vanad fonogramminumbrid.>', 1, 4449),
    ('ERA III 1, 13 (8)', 'ERA II 10, 729 (7)', NULL, NULL, 'XIII 282', 1, 1, 1, NULL, '<Kontrollitud: T. O. Pole klassikaline 2-realine viis: Siin on küll 16 pos-i, aga teksti struktuur on teistsugune: värsi esimene pool kordub 3 x ja järgneb lõpp.>', 1, 1356),
    ('ERA III 1, 130 (5)', 'ERA II 21, 170 (11)', 'ERA, Fon. 262 b', NULL, 'I 571', 1, 1, 1, NULL, '<Helisalvestus: Selge, tekstist ja noodist pikem>
    <Kontrollitud: T. O. Lisasin ka midagi (teksti viite?) Noodi ja teksti juures vanad fonogramminumbrid.>', 1, 189),
    ('ERA III 1, 130 (7)', 'ERA II 21, 171 (12)', 'ERA, Fon. 262 c', NULL, 'I 32', 1, 1, 1, NULL, '<Helisalvestus: Arusaadav, noodist pikem>
    <Kontrollitud: T. O. Lisasin teksti viite, parandasin vormi. Ei ole noodistatud salvestuselt. Noodi ja teksti juures vanad fonogramminumbrid.>', 1, 4528),
    ('ERA III 1, 132 (11)', 'ERA II 21, 175/7 (17)', 'ERA, Fon. 264 b', NULL, NULL, 1, 1, 1, NULL, '<Helisalvestus: Selge, noodist pikem, tekst veel pikem>
    <Kontrollitud: T. O. Lisasin teksti viite, laulutüübi. Noodi ja teksti juures vanad fonogramminumbrid.>', 1, 188),
    ('ERA III 1, 132 (13)', 'ERA II 21, 179 (19)', 'ERA, Fon. 265 a, b', NULL, 'XV 335', 1, 1, 1, NULL, '<Helisalvestus: Heli ei ole enam, fonogramm katki>
    <Kontrollitud: T. O. Parandasin esitaja nime Kõigesaar. Nooti on vist täiendatud heli järgi. Noodi ja teksti juures vanad fonogramminumbrid.>', 1, 3823),
    ('ERA III 1, 133 (15)', 'ERA II 21, 181/2 (23)', 'ERA, Fon. 265 c', NULL, 'XV 396', 1, 1, 1, NULL, '<Helisalvestus: Heli ei ole enam, fonogramm katki>
    <Kontrollitud: T. O. Nooti on ilmselt Koch fonogrammi järgi hiljem täpsustanud. Noodi ja teksti juures vanad fonogramminumbrid.>', 1, 3865),
    ('ERA III 1, 134 (17)', 'ERA II 21, 184 (25)', 'ERA, Fon. 266 b', NULL, 'II 211', 1, 1, 1, NULL, '<Helisalvestus: Selge, noodist pikem, vastab tekstile>
    <Kontrollitud: T. O. Lisasin teksti viite. Noodialune tekst erineb teistest: "mardisandid". Teksti ja nooti on ilmselt Koch fonogrammi järgi hiljem täpsustanud. Noodi ja teksti juures vanad fonogramminumbrid.>', 1, 368),
    ('ERA III 1, 135 (19)', 'ERA II 21, 185/6 (27)', 'ERA, Fon. 267 b', NULL, 'II 331', 1, 1, 1, NULL, '<Helisalvestus: Väga ilus esitus, selge, noodist pikem, veidi erineb tekstist>
    <Kontrollitud: T. O. Lisasin teksti viite, stroofi vormi. Teksti ja nooti on ilmselt Koch fonogrammi järgi hiljem täpsustanud. Tekst ja heli võivad olla eri variandid. Noodi ja teksti juures vanad fonogramminumbrid.>', 1, 387),
    ('ERA III 1, 135 (20)', 'ERA III 136/7 (28)', 'ERA, Fon. 268 a, b', NULL, 'VIII 251', 1, 1, 1, NULL, '<Helisalvestus: Selge, ilus, tekstist erinev variant.>
    <Kontrollitud: T. O. See on järjekindel 4-realine viis, ei kuulu siia. Tekst ja noot ei vasta helile, mis on pikem ja lauldakse teise struktuuriga. Lisasin teksti viite, vormi. Noodi ja teksti juures vanad fonogramminumbrid.>', 1, 2404),
    ('ERA III 1, 136 (24)', 'ERA II 21, 189/90 (32)', NULL, NULL, 'XV 445', 1, 1, 1, NULL, '<Kontrollitud: T. O. Parandasin lauliku nime: Granberg. Noodi ja teksti juures vanad fonogramminumbrid.>', 1, 3894),
    ('ERA III 1, 137 (28)', 'ERA II 21, 193/4 (38)', 'ERA, Fon. 269 a', NULL, 'VIII 231', 1, 1, 1, NULL, '<Helisalvestus: Heli ei ole enam, fonogramm katki>
