    ('ERA III 1, 137 (29)', 'ERA II 21, 195/7 (40)', 'ERA, Fon. 266 c', NULL, 'VIII 159', 1, 1, 1, NULL, '<Helisalvestus: Selge, ilus, tekstist ja noodist veidi erinev variant.>
    <Kontrollitud: T. O. Lisasin teksti viite, esitaja nime ja andmed. Tekst ja heli/noot eri variandid (2 või 3), heli on noodist pikem, aga noodi variatsiooni pole mujal. Noodi ja teksti juures vanad fonogramminumbrid.>', 1, 2298),
    ('ERA III 1, 138 (33)', 'ERA II 21, 202/3 (44)', 'ERA, Fon. 270 a', NULL, 'VI 773', 1, 1, 1, NULL, '<Helisalvestus: Selge, noodist pikem, tekst veel pikem.>
