    ('ERA III 1, 147 (61)', 'ERA II 21, 229 (79)', NULL, NULL, 'X 87', 1, 1, 1, NULL, '<Kontrollitud: T. O. Lisasin teksti viite, parandasin valla.>', 1, 2874),
    ('ERA III 1, 147 (62)', 'ERA II 21, 229/30 (80)', NULL, NULL, 'XII 358 / 363', 1, 1, 1, NULL, '<Kontrollitud: T. O. Lisasin teksti viite>', 1, 4410),
