    ('ERA III 1, 337', 'ERA II 21, 161/2 (3)', 'ERA, Fon. 260 a', NULL, 'X 270', 1, 1, 1, NULL, '<Helisalvestus: Salvestusel kaks varianti: kiirem, segasem (lühike) ja aeglasem, selgem (pikem). Arusaadav. Originaalis heli kohta: "rulli algus, hiljem segane" (noot), "kiirus 2/3, endise 1/4 asemel, fonogr. nõrk" (tekst).>
    <Kontrollitud: T. O. Noodistatud fonogrammi järgi, aga pole täpne. Lisasin teksti viite,>', 1, 3020),
    ('ERA III 1, 35 (50)', 'ERA II 6, 348 (7)', NULL, NULL, 'VI 217', 1, 1, 1, NULL, '<Kontrollitud: T. O. Lisasin teksti viite, parandasin vormi AA. Viisi vorm ei ole kindel 2-realine, sest on noodistatud 3 värssi.>', 1, 856),
    ('ERA III 1, 36 (53)', 'ERA II 7, 394 (8)', NULL, NULL, 'XIII 505', 1, 1, 1, NULL, '<Kontrollitud: T. O. Laulutüübiks oli keegi pannud "Laisa naise tapmine" (!). Lisasin teksti viite jm andmed, muutsin tüübi. Noot jätab ka võimaluse, et see on 4-realine viis. Vrdl ERA III 1, 38 (59+60)>', 1, 1813),
    ('ERA III 1, 37 (56)', 'N', NULL, NULL, 'VI 365', 1, 1, 1, NULL, '<Kontrollitud: T. O.>', 1, 958),
    ('ERA III 1, 38 (59, 60)', 'ERA II 6, 170/1 (2)', NULL, NULL, 'XIII 506', 1, 1, 1, NULL, '<Kontrollitud: T. O. Noot jätab võimaluse, et see on ka 4-realine viis. Vrdl ERA III 1, 36 (53). Teksti üleskirjutus on tehtud vist eraldi, kui viisikogujat polnud kohal.>', 1, 1814),
    ('ERA III 1, 38 (59, 60)', 'ERA II 7, 395/6 (13)', NULL, NULL, 'XIII 506', 1, 1, 1, NULL, '<Kontrollitud: T. O. Noot jätab võimaluse, et see on ka 4-realine viis. Vrdl ERA III 1, 36 (53).>', 1, 1815),
