    ('ERA III 1, 43 (64)', 'ERA II 6, 173 (9)', NULL, NULL, 'XI 207', 1, 1, 1, NULL, '<Kontrollitud: T. O. Arvatavasti viis ja tekst kirjutatud eri esituste järgi.>', 1, 3166),
    ('ERA III 1, 43 (65)', 'ERA II 7, 396 (15)', NULL, NULL, 'VI 204', 1, 1, 1, NULL, '<Kontrollitud: T. O. Lisasin teksti viite, täiendasin andmeid.>', 1, 847),
    ('ERA III 1, 47 (77)', 'ERA II 7, 397 (20)', NULL, NULL, 'VI 649', 1, 1, 1, NULL, '<Kontrollitud: T. O. Lisasin teksti viite, esitaja andmeid, kasutasin ka ERA II 6, 537.>', 1, 1090),
    ('ERA III 1, 51 (89)', 'ERA II 6, 538 (1)', NULL, NULL, 'X 98', 1, 1, 1, NULL, '<Kontrollitud: T. O. Tekst kogus ja noodi all veidi erinevad. Teksti üleskirjutus võib olla dikteeritud, sest pole esitusega seotud lisasilpe märgitud. Täiendasin andmeid.>', 1, 2881),
    ('ERA III 1, 52 (93)', 'ERA II 6, 544/5 (2) / ERA II 7, 409 (93)', NULL, NULL, 'XIII 431', 1, 1, 1, NULL, '<Kontrollitud: T. O. Parandasin esitaja soo :-), täiendasin andmeid. Lisasin teise teksti viite, tekstid erinevad üksikutes detailides.>', 1, 1632),
    ('ERA III 1, 52 (95)', 'ERA II 6, 551/2 (7) / ERA II 7, 410 (36)', NULL, NULL, 'XIII 635', 1, 1, 1, NULL, '<Kontrollitud: T. O. Täiendasin andmeid. Lisasin teise teksti viite, tekstid võivad olla erinevad esitused. Rütm on pikendusega rõhulistel nootidel, märgitud punkteeritud noodiga, viimase takti rütm on erinev - kombineerisin kahest rütmitüübist. Kontrollisin üle 5.01.2021>', 1, 2090),
    ('ERA III 1, 52 (96)', 'ERA II 6, 572/4 (18-22)', NULL, NULL, 'II 386', 1, 1, 1, NULL, '<Kontrollitud: T. O. Täiendasin andmeid. Ilmselt lauldi kogu mardilaulude tsükkel, mis siin on eri numbrite all, ühe viisiga. Eraldi viited on ERA II 6, 572 (18), 572/3 (19), 573 (20), 573/4 (21), 574 (22). Otsingu jaoks peaks nendest tegema eraldi viited? Rütm on pikendusega rõhulistel nootidel, märgitud punkteeritud noodiga, viimane takt erinev. Muutsin siin laulu nr 95 eeskujul rütmitüübi, mis enne oli 1. Kontrollisin üle 5.01.2021>', 1, 440),
    ('ERA III 1, 54 (102)', 'ERA II 6, 440 (1)', NULL, NULL, 'X 174', 1, 1, 1, NULL, '<Kontrollitud: T. O.>', 1, 3145),
    ('ERA III 1, 55 (104)', 'ERA II 6, 447 (1)', NULL, NULL, 'VI 295, VI 255.1', 1, 1, 1, NULL, '<Kontrollitud: T. O. Lisasin teksti viited (teise võtsin viisiduplikaadist), täiendasin esitaja andmeid. Laulmisel on silbid redutseerunud, võrreldes teksti üleskirjutusega - kas ehk tekst on kirjutatud dikteerimise järgi? VI 255 järel asendasin VI 255.1. 31.07.2020.>', 1, 902),
    ('ERA III 1, 55 (104)', 'ERA II 7, 416 (48)', NULL, NULL, NULL, 1, 1, 1, NULL, '<Kontrollitud: T. O.>', 1, 1063),
    ('ERA III 1, 58 (114)', 'ERA II 6, 427 (23)', NULL, NULL, 'VIII 154', 1, 1, 1, NULL, '<Kontrollitud: T. O. Siin on samal välitööl kogutud sama laulu kattuvad tekstivariandid (erinevus detailides) tehtud eri kirjeteks, teistel juhtudel mitte. Vrdl. ERA III 1, 52 (93, 95, 96). Kas panna siin ka kokku? Kas panna siin ka kokku? Vrdl ERA II 7, 419 (53)>', 1, 2292),
    ('ERA III 1, 58 (114)', 'ERA II 7, 419 (53)', NULL, NULL, 'VIII 154', 1, 1, 1, NULL, '<Kontrollitud: T. O. Siin on samal välitööl kogutud sama laulu praktiliselt kattuvad tekstivariandid (erinevus detailides) tehtud eri kirjeteks, eelmistel juhtudel mitte ERA III 1, 52 (93, 95, 96). Kas panna siin ka kokku? Vrdl ERA II 6, 427 (23)>', 1, 2293),
    ('ERA III 1, 63 (119)', 'ERA II 7, 419 (55)', NULL, NULL, 'VI 802', 1, 1, 1, NULL, '<Kontrollitud: T. O. See ei ole 2-realine regiviis, on ringmängu vahelaul: värss ja refrään>', 1, 1111),
    ('ERA III 1, 64 (125)', 'N', NULL, NULL, '389', 1, 1, 1, NULL, '<Kontrollitud: T. O. See ei ole 2-realine regiviis, on uuem, ei ole regilaul>', 1, 4127),
    ('ERA III 1, 66 (131)', 'N', NULL, NULL, 'VI 348', 1, 1, 1, NULL, '<Kontrollitud: T. O. Lisasin esitaja andmeid>', 1, 943),
