    ('ERA III 6, 129 (1)', 'EStk 15, 165/6 (116)', 'ERA, Fon. 337 a', NULL, 'IX 95', 1, 1, 1, '<Taive Särg "Karksi vanad rahvalaulud" 2008>', '<Kontrollitud: T. O. 24.02.2021 Need viisi viited tuleb tõsta noodistuste hulka.>', 1, 2595),
    ('ERA III 6, 131 (3)', 'EStk 15, 37/8 (30)', 'ERA, Fon. 336 c', NULL, 'IX 215', 1, 1, 1, '<Taive Särg "Karksi vanad rahvalaulud" 2008>', '<Kontrollitud: T. O. 24.02.2021 Need viisi viited tuleb tõsta noodistuste hulka.>', 1, 2654),
    ('ERA III 6, 133 (2)', 'ERA III 6, 133 (2)', 'ERA, Fon. 332', NULL, 'XIV 500', 1, 1, 1, '<Udo Kolk "Regiviiside varieerumisest" (1984: 63/4) - osaliselt noodistatud>', '<Helisalvestus: fonogramm katki, noodistused osalised>
    <Kontrollitud: T. O. Lisasin andmed: esitaja, koguja jm (siin polnud isegi kuulsa Liisu Mägi nime!) põhiliseks allikaks Kolk, Udo "Regiviiside varieerumisest" 1984. Ei tea, kas Loorits noodistas fonogrammilt, Kolk küll. Otsisin teksti kõikjalt peale EÜSI kogu.>', 1, 3490),
    ('ERA III 6, 134 (5)', NULL, 'ERA, Fon. 335 a', NULL, 'XIV 728', 1, 1, 1, '<Udo Kolk "Regiviiside varieerumisest" (1984: 66) on salvestuselt osaliselt noodistanud neid värsse, mida Loorits pole noodistanud.>', '<Helisalvestus: kohati segane, 16 värssi>
    <Kontrollitud: T. O. Lisasin andmed: esitaja, koguja jm (siin polnud isegi kuulsa Liisu Mägi nime!), põhiliseks allikaks Kolk, Udo "Regiviiside varieerumisest" 1984. Et Looritsal teksti pole ja viis on skemaatiline, siis ei tea, kas Loorits noodistas fonogrammilt. Otsisin teksti kõikjalt peale EÜSi kogu.>', 1, 3601),
    ('ERA III 6, 136 (5)', 'ERA II 10, 645 (5)', 'ERA, Fon. 313 e', NULL, 'VI 350', 1, 1, 1, NULL, '<Helisalvestus: selge, kattub noodistusega>
    <Kontrollitud: T. O. Salvestuse järgi noodistatud või kontrollitud. Lisasin teksti viite. Tekst kirjutatud aasta varem, pisikeste erinevustega.>', 1, 945),
    ('ERA III 6, 139 (2)', 'N', 'ERA, Fon. 329 b', NULL, NULL, 1, 1, 1, NULL, '<Helisalvestus: selge, rohkem sõnu kui noodis>
    <Kontrollitud: T. O. Setu 9-sibiline värss (ühe lisasilbiga). Panin rütmitüübi 6.12.2020>', 1, 4217),
    ('ERA III 6, 163 (1)', 'ERA III 6, 163 (1)', NULL, NULL, 'VII', 1, 1, 1, NULL, '<Kontrollitud: T. O.>', 1, 1034),
    ('ERA III 6, 18/19 (13)', 'ERA II 30, 59/60 (41)', 'ERA, Fon. 305 g', NULL, 'II 339', 1, 1, 1, NULL, '<Helisalvestus: keskmiselt arusaadav, noodistus vastab salvestusele, kuid selles on häälikute ja helikõrguste erinevusi - noodistuse vigu? Laul jääb ilmselt pooleli, tekst on pikem.>
    <Kontrollitud: T. O. Parandasin viisi viite, lisasin teksti viite, parandasin rütmitüübi jm. 6.12.2020>', 1, 399),
    ('ERA III 6, 184 (6)', 'ERA II 35, 161 (1)', 'ERA, Fon. 339 d', NULL, 'XII 424', 1, 1, 1, NULL, '<Helisalvestus: Selge, kattub noodi ja tekstiga.>
    <Kontrollitud: T. O. Võib olla salvestuse järgi noodistatud. Lisasin salvestuse viite.>', 1, 4445),
    ('ERA III 6, 185 (12)', 'ERA III 6, 185 (12) / ERA II 173/4 (1)', 'ERA, Fon. 339 g', NULL, 'XIII 232', 1, 1, 1, NULL, '<Helisalvestus: kahisev, enam-vähem arusaadav, kõik värsid ei kattu noodistusega>
    <Kontrollitud: T. O. Võib olla noodistust salvestuse järgi kontrollitud, kuid mõlemas on ka erinevaid värsse. Pikk tekst. Lisasin salvestuse ja teksti viite. Teksti juures on vana heliviide.>', 1, 1331),
    ('ERA III 6, 186 (14)', 'ERA II 35, 175/6 (2)', 'ERA, Fon. 340 b', NULL, 'XII 423', 1, 1, 1, NULL, '<Helisalvestus: selge, kattub üldjoontes noodiga>
    <Kontrollitud: T. O. Võib olla salvestuse järgi noodistatud. Lisasin salvestuse viite. Teksti juures on vana heliviide.>', 1, 4444),
    ('ERA III 6, 187 (18)', 'ERA II 35, 182/7 (5)', 'ERA, Fon 340 a', NULL, '411', 1, 1, 1, NULL, '<Helisalvestus: selge, 4 värssi>
    <Kontrollitud: T. O. Laul algab eeltaktiga ja lõppeb 7-silbilise reaga, näeb UL moodi välja. Noodistus vastab pigem 3.-4. värsile. Lisasin heli ja teksti viite.>', 1, 4053),
    ('ERA III 6, 188 (21)', 'ERA II 35, 191 (9)', 'ERA, Fon 340 e', NULL, 'IX 360', 1, 1, 1, NULL, '<Helisalvestus: helisalvestus on tehtud teise variandi järgi, selge>
