    ('ERA III 6, 189 (23)', 'ERA II 35, 197 (2)', 'ERA, Fon. 341 b', NULL, 'VI 383', 1, 1, 1, NULL, '<Helisalvestus: heli kattub noodi ja tekstiga, selge>
