    ('ERA III 6, 206 (55)', NULL, NULL, NULL, 'X 295', 1, 1, 1, NULL, '<Kontrollitud: T. O. Üks 11-silbiline värss, 9-11 positsiooni - see pole 2-realine viis. Rütmitüüp peab tulema L. Täpsustasin andmeid. 24.02.2021.>', 1, 3040),
    ('ERA III 6, 209 (63)', 'ERA II 35, 436 (15)', NULL, NULL, 'XV 291', 1, 1, 1, NULL, '<Kontrollitud: T. O. Viisis 12 positsiooni, värsialguse kordus. Pole 2-realine viis. Lisasin esitaja nime ja andmed, 24.02.2021>', 1, 3786),
    ('ERA III 6, 21 (18)', 'ERA II 30, 32 (8)', NULL, NULL, 'I 731', 1, 1, 1, NULL, '<Kontrollitud: T. O. Lisasin andmeid teksti kogumise, lauliku kohta.>', 1, 238),
    ('ERA III 6, 21 (19)', 'ERA II 30, 31 (7)', NULL, NULL, 'I 730', 1, 1, 1, NULL, '<Kontrollitud: T. O. Lisasin andmeid teksti kogumise, lauliku kohta.>', 1, 237),
    ('ERA III 6, 210 (68)', 'ERA II 35, 231/2 (1)', NULL, NULL, 'XI 187', 1, 1, 1, NULL, '<Kontrollitud: T. O. Lisasin teksti viite. Teksti juures antud viisi nr ei kehti, sest viiside numbreid on hiljem muudetud.>', 1, 3154),
    ('ERA III 6, 211 (74, 75)', 'N', NULL, NULL, '63', 1, 1, 1, NULL, '<Kontrollitud: T. O.>', 1, 4001),
