    ('ERA III 6, 227 (114)', 'ERA II 35, 593/4 (8)', 'ERA, Fon. 349 b', NULL, 'XII 420', 1, 1, 1, NULL, '<Helisalvestus: Algus segane, 4 värssi, kattub noodiga>
