    ('ERA III 6, 23 (24)', 'ERA II 30, 111 (7)', NULL, NULL, 'II 357', 1, 1, 1, NULL, '<Kontrollitud: T. O. Lisasin teksti viite, andmeid teksti kogumise (koguja nimi), lauliku kohta.>', 1, 414),
    ('ERA III 6, 232 (130)', 'ERA II 35, 507 (8)', NULL, NULL, 'XIV 659', 1, 1, 1, NULL, '<Kontrollitud: T. O. Lisasin lauliku sünnikoha, otsisin vastavat teksti.>', 1, 3565),
    ('ERA III 6, 238 (154)', 'ERA II 36, 110 (9)', 'ERA, Fon. 350 c', NULL, 'I 888', 1, 1, 1, NULL, '<Helisalvestus: Vaikne, selge, kõnelähedane esitus, kattub üldjoontes noodistuse ja tekstiga. Noodis 2 värssi, mujal 4.>
    <Kontrollitud: T. O. Lisasin teksti viite ja esitaja andmeid tekstikogust. Tekst on kirjutatud fonogrammi järgi, viisi võib olla kontrollitud.>', 1, 4571),
    ('ERA III 6, 247 (163)', 'ERA II 36, 219/20 (1)', 'ERA, Fon. 351 c', NULL, 'IX 284', 1, 1, 1, NULL, '<Helisalvestus: Alguses ja hiljem kohati arusaamatu, tempo muutub. Pikkuselt vastab tekstile.>
    <Kontrollitud: T. O. Parandasin esitaja nime (oli Latim). Tekst on kirjutatud fonogrammi järgi, viis võib-olla ka. Ktr Erastveret fonogrammide registrist. T. S.>', 1, 2708),
    ('ERA III 6, 247 (165)', 'ERA II 36, 222/3 (5)', 'ERA, Fon. 351 e', NULL, 'XII 419', 1, 1, 1, NULL, '<Helisalvestus: Segane, müraga, tempo muutub. 8 värssi, noodistus 4 värssi, tekst pikem.>
    <Kontrollitud: T. O. Lisasin märkusi, andmeid. Tekst on osalt kirjutatud fonogrammi järgi (F.), osalt dikteeritud (D.). Ktr Erastveret fonogrammide registrist. T. S.>', 1, 4442),
    ('ERA III 6, 25 (29)', 'ERA II 30, 145/6 (2) / ERA III 6, 25 (29)', 'ERA, Fon. 306 b1', NULL, 'II 195', 1, 1, 1, '<VK VIII>', '<Helisalvestus: Selge heli. Füüsiliselt on üks salvestus (306 b) ja üks tekst (145/6 (2), mis ei ole jagatud, kuid nad vastavad kahele eri noodile ERA III 6, 25 (29) ja (30). Siinsele noodile vastab salvestuse ja teksti algusosa.>
    <Kontrollitud: T. O. Lisasin teksti viite, noodistaja ja litereerija andmed oli tabelisse kirjutanud ilmselt Edna Tuvi. Tekst on kirjutatud vähemalt kahe esituse põhjal.>', 1, 140),
    ('ERA III 6, 25 (30)', 'ERA II 30, 145/6 (2) / ERA III 6, 25/6 (29, 30)', 'ERA, Fon. 306 b2', NULL, 'II 194', 1, 1, 1, '<VK VIII>', '<Helisalvestus: Selge. Füüsiliselt on üks salvestus (306 b) ja üks tekst (145/6 (2), mis ei ole jagatud, kuid nad vastavad kahele eri noodile ERA III 6, 25 (29) ja (30). Siinsele noodile vastab salvestuse ja teksti lõpuosa, lk 146.>
    <Kontrollitud: T. O. Lisasin teksti viite, noodistaja ja litereerija andmed oli tabelisse kirjutanud ilmselt Edna Tuvi. Tekst on kirjutatud vähemalt kahe esituse põhjal.>', 1, 4577),
    ('ERA III 6, 251 (180)', 'ERA II 36, 233/4 (1)', 'ERA, Fon. 352 b', NULL, 'IX 248', 1, 1, 1, NULL, '<Helisalvestus: Enam-vähem. Tekst on kirjutatud teise variandi järgi.>
    <Kontrollitud: T. O. Parandasin esitaja Latui??. Noodistuse juurde on originaalis märgitud vale esitaja, samuti on viga nootide ja fonogrammide registris - Juhan Latik. Noot vastab fonogrammile ja sealt kuuleb selgesti, et naine laulab, ja sama variandi tekst on tekstikogus naise nimega.>', 1, 2679),
    ('ERA III 6, 26 (31)', 'ERA II 30, 145 (1)', 'ERA, Fon. 306 c', NULL, '378', 1, 1, 1, '<VK VIII>', '<Helisalvestus: Kena, veidi erineb noodist, tekstiga kattub.>
    <Kontrollitud: T. O. Võib olla ka 4-realine viis. Pigem riimiline laul. Noot on tõeneäoliselt tehtud välitöödel. Lisasin teksti viite.>', 1, 4051),
    ('ERA III 6, 26 (34)', 'ERA II 30, 150 (9)', 'ERA, Fon. 306 f', NULL, NULL, 1, 1, 1, '<VK VIII>', '<Helisalvestus: Kena, kattub noodi ja tekstiga.>
    <Kontrollitud: T. O. Muutsin vormi tähistuse (oli 1x2 ?) heli järgi AA. Vorm on noodis ja helis veidi erinev.>', 1, 142),
    ('ERA III 6, 263 (11)', NULL, NULL, NULL, 'IV 358', 1, 1, 1, NULL, '<Kontrollitud: T. O.>', 1, 545),
    ('ERA III 6, 275 (1)', 'E, StK 3, 26 (2)', NULL, NULL, 'XII 417', 1, 1, 1, NULL, '<Kontrollitud: T. O. Parandasin viisi viite, oli EÜS III 6, 275 (1). 7.12.2020 Lisasin teksti viite, laulja ja koguja andmed. 24.02.2021>', 1, 4441),
    ('ERA III 6, 275 (2)', 'E, StK 3, 35 (11)', NULL, NULL, 'IV 410', 1, 1, 1, NULL, '<Kontrollitud: T. O. Viis on üles kirjutatud 1923, saadetud 1933. Lisasin teksti viite ja andmed, laulja ja koguja andmed. 24.02.2021>', 1, 590),
    ('ERA III 6, 275 (6)', 'E, StK 3, 42 (18)', NULL, NULL, '139', 1, 1, 1, NULL, '<Kontrollitud: T. O. Viis on üles kirjutatud 1923, saadetud 1933. Lisasin teksti viite ja andmed, laulja ja koguja andmed. 24.02.2021>', 1, 4028),
    ('ERA III 6, 276 (9)', 'E, StK 3, 57/58 (2)', NULL, NULL, 'V 104', 1, 1, 1, NULL, '<Kontrollitud: T. O. Viis on üles kirjutatud 1923, saadetud 1933. Laulja vanuses on vastuolu. Lisasin teksti viite ja andmed.>', 1, 736),
    ('ERA III 6, 34 (44)', 'ERA II 30, 111 (7)', 'ERA, Fon. 310 d', NULL, '370', 1, 1, 1, NULL, '<Kontrollitud: T. O. Lisasin teksti viite. See ei ole regilaul, nt 1. värss 6 silpi, 2.on 5 silpi, hiljem tuleb värsse:" Vaivab mind siin kurptus, nutan alati.">', 1, 4123),
    (NULL, 'ERA II 29, 251/5 (1) / ERA II 29, 263/5 (1, 2)', 'ERA, Fon. 315 a', NULL, 'XIII 604', 1, 1, 1, NULL, '<Helisalvestus: Arusaadav, langeb detailides kokku noodistusega, kuid on üksikuid erinevaid noote, tekstist 5 varianti, salvestusel tekst 1b.>
    <Kontrollitud: T. O. Täiendasin viidet, lisasin salvestuse viite, kogujaid. Noodistatud (või kontrollitud) on salvestuse järgi (detailides suur kokkulangevus). Originaalis ei ole eristatud kahe üleskirjutaja tekste samast esitusest ega nimetatud nende nimesid. Parandasin vanus (oli 86). Muutsin siin rütmitüübi 1 ära hiljem. 23.02.2021>', 1, 2022),
    (NULL, 'ERA II 29, 257/261 (2) / ERA II 29, 266/268 (3)', 'ERA, Fon. 315 b', NULL, 'X 271', 1, 1, 1, NULL, '<Helisalvestus: Arusaadav, vastab noodistusele, tekstist mitu varianti, salvestusel tekst 2b. Noodistus algab salvestuse 2. värsist.>
    <Kontrollitud: T. O. Noodistatud (või kontrollitud) on salvestuse järgi, detailides suur kokkulangevus. Originaalis ei ole eristatud kahe üleskirjutaja tekste samast esitusest ja pole kõrval nende nimesid. Kirjutasin märkustesse. Parandasin vanus (oli 86). Muutsin rütmitüübi, oli 7.>', 1, 3021),
    (NULL, 'ERA II 29, 281 V / ERA II 29, 283 V', 'ERA, Fon. 316 a', NULL, 'VIII 469', 1, 1, 1, NULL, '<Helisalvestus: Peaaegu arusaadav, algus ja lõpp segased, noot samasugune.>
    <Kontrollitud: T. O. Noodistatud (või kontrollitud) on salvestuse järele, detailides on suur kokkulangevus. Originaalis ei ole eristatud kahe üleskirjutaja tekste ühest ja samast esitusest ega üleskirjutajate nimesid. Tegin ise tähistused: A Viidalepp, B Ariste. Täiendasin rütmitüüpi, oli 5. 10.01.2021>', 1, 2526),
    (NULL, 'ERA II 29, 285 VI (a,b) / ERA II 29, 287 VI (a,b)', 'ERA, Fon. 316 b', NULL, 'IX 219', 1, 1, 1, NULL, '<Helisalvestus: Digi- ega magnetofonikoopiat pole: "lindil pole" (register)>
    <Kontrollitud: T. O. Noodistas Leichter arvatavasti salvestuse abil. Kaks tekstivarianti, kummalgi a ja b osa. Originaalis ei ole eristatud kahe üleskirjutaja tekste samast esitusest ega nende nimesid. Tegin ise tähistused: A Viidalepp, B Ariste. Parandasin viisi viite, ERA III 6, 83 (24), lisasin heli puudumise märkuse. Muutsin rütmi tüüpi (oli 1). Nüüd lihtsustasin, tegin 5/5F-st lihtsalt 5. 10.01.2021>', 1, 2656),
    ('ERA III 6, 86 (7)', 'ERA II 29, 297 IX / ERA II 29, 299/301 IX', 'ERA, Fon. 316 e', NULL, 'VII 145', 1, 1, 1, NULL, '<Helisalvestus: Peaaegu arusaadav, viis ei vasta täpselt noodile ja on värsikese pikem, tekst veel pikem.>
    <Kontrollitud: T. O. Noodistas Leichter, ta võis kasutada salvestuse abi. Lisasin teksti viite. Originaalis ei ole eristatud kahe üleskirjutaja tekste samast esitusest ega nende nimesid. Tegin ise tähistused: A Viidalepp, B Ariste.>', 1, 985),
    ('ERA III 7, 101 (40)', 'N', NULL, NULL, 'VI 344', 1, 1, 1, NULL, '<Kontrollitud: T. O.>', 1, 940),
    (NULL, 'ERA II 56, 194/5 (3)', 'ERA, Fon. 380 b', NULL, 'VI 260', 1, 1, 1, NULL, '<Helisalvestus: Peaaegu arusaadav, viis vastab üldjoontes noodile, pisiasjades erinev - ja helirida on erinev!>
    <Kontrollitud: T. O Lisasin teksti viite. Noot ja tekst kattuvad, on ehk üks esitus, helisalvestus võib olla ka neile väga sarnane teine esitus. See kirje on topelt, ka viis nr 1061 ja kaardi nr 1133, kustutasin teise. 31.07.2020.>', 1, 4613),
    (NULL, 'ERA II 115, 115/6 (3)', 'ERA, Fon. 439 b', NULL, 'IV 367', 1, 1, 1, NULL, '<Helisalvestus: Selge, noodistus vastab detailides salvestusele.>
    <Kontrollitud: T. O. Ilmselt noodistatud salvestuselt, tekst kirjutatud teise esitusvariandi järgi. Lisasin teksti viite.>', 1, 554),
    (NULL, 'ERA II 115, 138/9 (32)', 'ERA, Fon. 442 c', NULL, 'IV 416', 1, 1, 1, NULL, '<Helisalvestus: Kahisev, noodistus vastab detailides salvestusele..>
