    ('ERA III 7, 145 (25)', 'ERA II 115, 183 (1)', NULL, NULL, 'XIII 279', 1, 1, 1, NULL, '<Kontrollitud: T. O. Lisasin teksti viite.>', 1, 1354),
    (NULL, 'ERA II 115, 185 (1)', 'ERA, Fon. 448 a', NULL, 'X 128', 1, 1, 1, NULL, '<Helisalvestus: Halvasti arusaadav, tempo muutub, noodist pikem, 10 värssi.>
