    (NULL, 'ERA II 115, 187 (4)', 'ERA, Fon. 449 a', NULL, 'XI114', 1, 1, 1, NULL, '<Helisalvestus: Arusaadav, noodistus vastab detailides salvestusele.>
    <Kontrollitud: T. O. Ilmselt noodistatud salvestuselt. Lisasin teksti viite. Rütitüüpi täpsustasin, oli 10.>', 1, 3121),
    (NULL, 'ERA II 115, 244/6 (7)', 'ERA, Fon. 454 c', NULL, 'VII 118', 1, 1, 1, '<Tampere ERlV III: 42-44>', '<Helisalvestus: Arusaadav, noodistus vastab detailides salvestusele.>
