    ('ERA III 7, 303 (18)', 'N', NULL, NULL, 'I 885', 1, 1, 1, NULL, '<Kontrollitud: T. O Gerda Laugaste isa on Karl Kink 1866-1946 (Geni). Siin oli viites vale 18a. Parandasin ka "juljused" asemele "kuljused". :-) Tekst on pigem nagu loitsu kõla imitatsioon, lisasin tekstitüübi.>', 1, 340),
    ('ERA III 7, 305 (22)', 'N', NULL, NULL, 'VII 150', 1, 1, 1, NULL, '<Kontrollitud: T. O See ei ole korrapärane 2-realine viis, see on 1-realine või isegi poolerealine viis erandliku lõpuosaga. Siin on ka pikk refrään. Ma ei võtaks 2-realiste hulka.>', 1, 986),
    ('ERA III 7, 313 (1)', 'ERA III 7, 313 (1)', NULL, NULL, 'I 588', 1, 1, 1, NULL, '<Kontrollitud: T. O Koguja nimi on ebatavaline, kas see on õige? Kust tuli kihelkonna nimi?>', 1, 193),
    ('ERA III 7, 313 (2)', 'ERA III 7, 313 (1)', NULL, NULL, 'I 589', 1, 1, 1, NULL, '<Kontrollitud: T. O Lauluteksti ei ole, kuid viis praktiliselt kattub eelmisega ja ilmselt on mõeldud ka, et eelmise tekst sobib. Kust tuli kihelkonna nimi?>', 1, 195),
    ('ERA III 7, 55 (22)', 'ERA, II 56, 91/2 (2)', 'ERA, Fon. 360 c', NULL, 'XIII 286', 1, 1, 1, NULL, '<Helisalvestus: Vaikne, kahiseb, tekst suht arusaamatu. Noot on helist lühem, tekst pikem.>
    <Kontrollitud: T. O Lisasin heli ja teksti viite, noodi juures on vana fonogramminumber.>', 1, 1359),
    ('ERA III 7, 64 (46)', 'ERA II 56, 43/5 (1)', 'ERA, Fon. 365 b', NULL, 'XII 352', 1, 1, 1, NULL, '<Helisalvestus: Kahiseb, kostab halvasti. Noot on helist lühem, tekst pikem. Tekst on kirjutatud sõltumatult, teise esituse järgi.>
    <Kontrollitud: T. O. Lisasin teksti viite, laulutüübi, noodi juures on vana fonogramminumber.>', 1, 4404),
    ('ERA III 7, 66 (51)', 'ERA II 56, 419/20 (10)', 'ERA, Fon. 367 d', NULL, 'VIII 268', 1, 1, 1, NULL, '<Helisalvestus: Kahiseb, peaaegu arusaadav. Noot on helist lühem, tekst pikem.>
    <Kontrollitud: T. O. Parandasin valla: Väike-Vändra. Noodi juures on vana fonogramminumber.>', 1, 2417),
    (NULL, 'ERA II 56, 420/1 (11)', 'ERA, Fon 371 b', NULL, 'XIII 519', 1, 1, 1, NULL, '<Helisalvestus: Kahiseb, kostab halvasti. Noodistatud on palju variatsioone, aga mitte kogu salvestust.>
