    (NULL, 'ERA II 56, 271/2 (2)', 'ERA, Fon. 388 a', NULL, 'VII', 1, 1, 1, NULL, '<Helisalvestus: Selge, vastab detailides noodistusele. Laul tervelt noodistatud.>
