    (NULL, 'ERA II 56, 272/3 (3)', 'ERA, Fon. 388 b', NULL, 'IV 88', 1, 1, 1, NULL, '<Helisalvestus: Selge, vastab detailides noodistusele ja tekstile. Laul tervelt noodistatud.>
