    (NULL, 'ERA II 56, 273 (4)', 'ERA, Fon. 388 c', NULL, 'II 354', 1, 1, 1, NULL, '<Helisalvestus: Selge, noodist pikem, vastab tekstile (5 värssi)>
    <Kontrollitud: T. O. Noot (1 värss) võib olla tehtud salvestuse põhjal. Noodi juures on vana fonogramminumber.>', 1, 412),
    ('ERA III 7, 94/5 (29)', 'ERA II 56, 278/9 (2)', NULL, NULL, 'IX 459', 1, 1, 1, NULL, '<Kontrollitud: T. O Tekst ja viis eri isikutelt.>', 1, 2803),
    ('ERA III 7, 96 (31)', 'ERA II 56, 281/3 (5)', NULL, NULL, 'XI 206', 1, 1, 1, NULL, '<Kontrollitud: T. O Täpsustasin stroofi vormi, see oli AB. Siin on formaalselt sama palju noote kui 2-realises viisis, kuid tegelikult on värss ja viis teistsuguse struktuuriga.>', 1, 3165),
    (NULL, 'ERA II 172, 18/9 (3)', 'ERA, Pl. 19 A1', NULL, 'XV 459', 1, 1, 1, NULL, '<Helisalvestus: Selge ja ilus>
    <Kontrollitud: T. O. Tõstsin viisi viite originaali kohalt noodistuste hulka, sest noodistus on helisalvestuse transkriptsioon. Noodistusest on mustand ja täpsustatud tekstiga (?) ümberkirjutus (RKM III 4). Kaardil viis vastab mustandile. Tekst ja heli ei kattu täpselt, on jäädvustatud eri esituste järgi. Muutsin laululiigi, lisasin laulutüübi. 21.02.2019>', 1, 3955),
    (NULL, 'ERA II 172, 28/9 (13)', 'ERA, Pl. 19 A3', NULL, 'XV 461', 1, 1, 1, NULL, '<Helisalvestus: Selge ja ilus>
    <Kontrollitud: T. O. Tõstsin viisi viite originaali kohalt noodistuste hulka, sest noodistus on helisalvestuse transkriptsioon. Noodistusest on mustand ja täpsustatud tekstiga (?) ümberkirjutus (RKM III 4). Kaardil viis vastab mustandile, aga heliga võrreldes väikseid vigu. Tekst ja heli ei kattu täpselt, on jäädvustatud eri esituste järgi. Lisasin laulutüübi. Muutsin laululiigi. 21.02.2019>', 1, 3956),
    (NULL, 'ERA II 172, 39/40 (22)', 'ERA, Pl. 19 B1', NULL, 'XV 462', 1, 1, 1, NULL, '<Helisalvestus: Selge ja ilus>
    <Kontrollitud: T. O. Tõstsin viisi viite originaali kohalt noodistuste hulka, sest noodistus on helisalvestuse transkriptsioon. Noodistusest on mustand ja täpsustatud tekstiga (?) ümberkirjutus (RKM III 4). Kaart vastab mustandile, hea noodistus, pisikesi ebatäpsusi. Tekst ja heli ei kattu täpselt, on jäädvustatud eri esituste järgi. Lisasin laulutüübi. Muutsin laululiigi. 21.02.2019>', 1, 3957),
    (NULL, 'ERA II 172, 40 (23)', 'ERA, Pl. 19 B2', NULL, 'XV 463', 1, 1, 1, NULL, '<Helisalvestus: Selge ja ilus>
    <Kontrollitud: T. O. Tõstsin viisi viite originaali kohalt noodistuste hulka, sest noodistus on helisalvestuse transkriptsioon. Noodistusest on mustand ja täpsustatud teksitga (?) ümberkirjutus (RKM III 4). Kaart vastab mustandile, hea noodistus, pisikesi ebatäpsusi. Tekst ja heli üsna kattuvad, aga on jäädvustatud eraldi. Muutsin laululiigi, lisasin laulutüübi. 21.02.2019>', 1, 3958),
    (NULL, 'ERA II 172, 29/30 (14)', 'ERA, Pl. 19 B3', NULL, 'XV 464', 1, 1, 1, NULL, '<Helisalvestus: Selge ja ilus>
    <Kontrollitud: T. O. Tõstsin viisi viite originaali kohalt noodistuste hulka, sest noodistus on helisalvestuse transkriptsioon. Noodistusest on mustand, täpsustatud tekstiga (?) ümberkirjutus (RKM III 4) ja kartoteegikaart. Kaart vastab mustandile, aga heliga võrreldes väikseid ebatäpsusi.Tekst ja heli ei kattu täpselt, on jäädvustatud eri esituste järgi. Muutsin laululiigi, lisasin laulutüübi. 21.02.2019>', 1, 4002),
    (NULL, NULL, 'ERA, Pl. 20 B3', NULL, 'XV 470', 1, 1, 1, NULL, '<Helisalvestus: Selge ja ilus>
    <Kontrollitud: T. O. Tõstsin viisi viite originaali kohalt noodistuste hulka, sest noodistus on helisalvestuse transkriptsioon. Noodistusest on mustand ja täpsustatud tekstiga (?) ümberkirjutus (RKM III 4). Kaart vastab mustandile, üsna hea noodistus. Lisasin laulutüübi. 21.02.2019>', 1, 3959),
    (NULL, 'ERA II 39, 87 (2)', 'ERA, Pl. 21 B1', NULL, 'XV 472', 1, 1, 1, NULL, '<Helisalvestus: Selge ja ilus>
    <Kontrollitud: T. O. Tõstsin viisi viite originaali kohalt noodistuste hulka, sest noodistus on helisalvestuse transkriptsioon. Noodistusest on mustand ja täpsustatud tekstiga (?) ümberkirjutus (RKM III 4.) Kaart vastab mustandile, aga heliga võrreldes väikseid vigu. Tekst on kogutud 5 a varem, aga peaaegu kattub heliga. Muutsin laululiigi, lisasin laulutüübi. 21.02.2019>', 1, 4003),
    (NULL, NULL, 'ERA, Pl. 21 B4', NULL, 'XV 474', 1, 1, 1, NULL, '<Helisalvestus: Selge ja ilus. Transkriptsioonil viis ja tekst täies pikkuses. 
    >
    <Kontrollitud: T. O. Tõstsin viisi viite originaali kohalt noodistuste hulka, sest noodistus on helisalvestuse transkriptsioon. Noodistusest on mustand ja täpsustatud tekstiga (?) ümberkirjutus (RKM III 4). Teksti otsingutest: ERA II 132, 30-67 POLE; 115 (11-23, 113-158) KATKI, VAATAMATA; 102 (36/7) POLE, 23 (259/61) POLE 21.02.2019.>', 1, 4004),
    (NULL, NULL, 'ERA, Pl. 24 A1', NULL, 'XV 475', 1, 1, 1, NULL, '<Helisalvestus: Selge ja ilus. Transkriptsioonil viis ja tekst täies pikkuses. 
    >
    <Kontrollitud: T. O. Tõstsin viisi viite originaali kohalt noodistuste hulka, sest noodistus on helisalvestuse transkriptsioon. Noodistusest on mustand ja täpsustatud tekstiga (?) ümberkirjutus (RKM III 4). 21.02.2019>', 1, 4005),
    (NULL, NULL, 'ERA, Pl. 28 A2', NULL, 'XV 486', 1, 1, 1, NULL, '<Helisalvestus: Selge ja ilus>
    <Kontrollitud: T. O. Tõstsin viisi viite originaali kohalt noodistuste hulka, sest noodistus on helisalvestuse transkriptsioon. Noodistusest on mustand ja ümberkirjutus. Parandasin viisi vormi, laululiigi (oli lüürika). Viis on varieeruv 1-realine, ei kuulu siia tabelisse. 21.02.2019>', 1, 4006),
    (NULL, NULL, 'ERA, Pl. 28 A3', NULL, 'XV 487', 1, 1, 1, NULL, '<Helisalvestus: Selge ja ilus>
    <Kontrollitud: T. O. Tõstsin viisi viite originaali kohalt noodistuste hulka, sest noodistus on helisalvestuse transkriptsioon. Noodistusest on mustand ja ümberkirjutus (RKM III 4). Parandasin viisi vormi, laululiigi (oli lüürika). 21.02.2019>', 1, 4007),
    (NULL, NULL, 'ERA, Pl. 29 A1', NULL, 'XV 490', 1, 1, 1, NULL, '<Helisalvestus: Selge ja väga-väga ilus>
    <Kontrollitud: T. O. Tõstsin viisi ja teksti viited originaalide kohalt noodistuste hulka. Noodistuseks märgitud ERA, Pl. 29 A1 on helisalvestuse transkriptsioon, teksti viiteks märgitud RKM III 4, 53/55 (1) on eelneva ümberkirjutus, mille nootides on tehtud mõned vead; teksti on vbl parandatud (ei võrrelnud.) 21.02.2019>', 1, 4008),
    ('SKS, Lähteenkorva nr. 354', 'SKS, Lähteenkorva nr. 354', NULL, NULL, 'VI 322', 1, 1, 1, '<ERv 113 (850)>', '<Kontrollitud: T. O. Käsikirja koopia on peaaegu kustunud. (Andmed olid sisestatud Launise raamatu järgi, kus oli märgitud khk, 1 värss ja ühtlustatud esitus E+K.)>', 1, 923),
    ('SKS, Lähteenkorva nr. 239', 'N', NULL, NULL, 'XV 239', 1, 1, 1, '<ERv 156 (1160)>', '<Kontrollitud: T. O. (Andmed olid sisestatud raamatu järgi, kus oli khk, 1 värss ja ühtlustatud esitus E+K.)>', 1, 3768),
