    ('SKS, Lähteenkorva nr. 280', NULL, NULL, NULL, 'XV 236', 1, 1, 1, '<ERv 168 (1250)>', '<Kontrollitud: 10 pos. Muutsin rütmitüüpi originaali põhjal, oli 1. Mõlemas värsipooles on lisasilp, seega vbl lisasilbiga viis. 19.02.2021>', NULL, 3765),
    ('SKS, Lähteenkorva nr. 314', NULL, NULL, NULL, 'XV 235', 1, 1, 1, '<ERv 169 (1257)>', '<Kontrollitud: T. O. Andmed olid sisestatud raamatu järgi, kus oli khk, 1 värss ja ühtlustatud esitus E+K. Andmebaasis oli märgitud esitus E+K - see võib olla raamatust (autori lisatud?), käsikirjast ei leia.>', 1, 3764),
