    ('EÜS IX 1279 (20/21)', 'N', 'ERA, Fon. 003 b', NULL, 'XIII 275', 1, 1, 1, NULL, '<Helisalvestus: Helisalvestusel sõnad arusaamatud, viis ei kattu täpselt noodiga. EÜS IX 1279 (20) vastab helisalvestuse osale ja on tekstiga, (21) on aga viisi jätk, mida salvestusel ei ole ja see on ilma tekstita.>
    <Kontrollitud: T. O. Lisasin heli viite. Noodistus on pikem kui helisalvestus ja nad ei kattu täpselt. Salvestus võis, aga ei pruukinud olla abiks noodi kirjutamisel. Esitaja elukoht oli enne märgitud Urvaste khk, Lutsa küla. Originaalis näen "sünd. Lutsa talus". Vbl elabki ta seal, aga seda pole otseselt öeldud. Täpsustasin rütmitüüpi, enne oli 5. 7.12.2020>', 1, 1350),
    ('EÜS IX 1279 (24)', NULL, 'ERA, Fon. 003 d', NULL, 'VIII 337', 1, 1, 1, NULL, '<Kontrollitud: T. O. Elukoht oli enne märgitud Urvaste khk, Lutsa küla. Originaalis näen "sünd. Lutsa talus". Vbl elabki ta seal, aga seda pole otseselt öeldud.>', 1, 2477),
    ('EÜS IX 1280 (28)', NULL, NULL, NULL, 'XI 152', 1, 1, 1, NULL, '<Kontrollitud: T. O. Elukoht oli enne märgitud Urvaste khk, Lutsa küla. Originaalis näen "sünd. Lutsa talus". Vbl elabki ta seal, aga seda pole otseselt öeldud.>', 1, 3138),
    ('EÜS IX 1281 (31)', 'EÜS IX 1280/1, 1299', 'ERA, Fon. 005 b', NULL, 'IV 374', 1, 1, 1, NULL, '<Kontrollitud: T. O Teksti viide pole kindel. Elukoht oli märgitud Hargla khk, aga see on sünnikoht (laulude õppimise koht?), Vana-Antsla vald ei ole Hargla khk. Noodistajat polnud, kuid panin Väisänen nagu teistelegi.>', 1, 561),
    ('EÜS IX 1291 (65)', 'N', 'ERA, Fon. 009 d', NULL, 'XIII 270', 1, 1, 1, NULL, '<Helisalvestus: Helisalvestus selge, vastab esimesele noodistusele.>
    <Kontrollitud: T. O Lisasin heli viite, sellele vastab esimene noodistus. Siin on kaks erinevat noodistust samast värsipaarist. Mõlemad eri rütmiga. 23.02.2021 Täpsustasin rütmitüüpi, oli 13&6. 7.12.2020.>', 1, 1346),
    ('EÜS IX 1292 (72)', 'N', 'ERA, Fon. 010 b', NULL, 'X 20', 1, 1, 1, NULL, '<Kontrollitud: T. O Elukoht oli märgitud: Sangaste v.>Vana-Antsla v. Rütmitüüp kontrollitud 7.12.2020>', 1, 3052),
    ('EÜS IX 1293 (76)', 'N', 'ERA, Fon. 010 e', NULL, '80', 1, 1, 1, NULL, '<Kontrollitud: T. O Rütmitüüp kontrollitud 7.12.2020>', 1, 4025),
    ('EÜS IX 1294 (79)', 'N', 'ERA, Fon. 011 a', NULL, 'XIV 559', 1, 1, 1, NULL, '<Kontrollitud: T. O Märkisin sama valla ka sünnikohana, sest seda oli eraldi mainitud. Täpsustasin rütmitüübi, enne oli 13. See viis oli siin topelt, kustutasin teise. Teise viisi nr oli 1349, kart. kaart XIII 273. 7.12.2020>', 1, 3520),
    ('EÜS IX 1295 (85)', 'N', 'ERA, Fon. 014 f', NULL, '77', 1, 1, 1, NULL, '<Kontrollitud: T. O Märkisin sama valla ka sünnikohana, sest seda oli eraldi mainitud. Vormi AB määrasin salvestuse põhjal.>', 1, 4024),
