    ('EÜS IX 1329 (208)', 'EÜS IX 1426/7 (2); EÜS IX 1522/3 (2, mustand)', 'ERA, Fon. 018 d', NULL, 'IX 288', 2, 1, 1, NULL, '<Helisalvestus: Fonogrammi pole, kuigi fonogrammi number ERA, Fon 018 d) on noodistuse juures>
    <Kontrollitud: T. O. Oli: Veera Kararenkova. Praegused eri nimekujud tulid viiside kogust ja nimekirjast. Parandasin rahvaks "vene", sest nii oli Väisänen märkinud. Kustutaksin helisalvestuse viite, sest salvestust ju ei ole. Teksti kogujana onlid andmebaasis märgitud Nirk, A./Tamm, R., 1912/1913, kuid originaalis on ainult Tamm 1912, nii ka parandasin.>', 1, 2709),
    ('EÜS IX 1329 (209)', 'EÜS IX 1427/8 (3)', NULL, NULL, 'XIII 306', 2, 1, 1, NULL, NULL, NULL, 1376),
    ('EÜS IX 1329 (210)', 'EÜS IX 1466 (54)', 'ERA, Fon. 018 e', NULL, 'XI 196', 2, 1, 1, NULL, '<Helisalvestus: Fonogrammi pole, kuigi fonogrammi number ERA, Fon 018 e) on noodistuse juures>
    <Kontrollitud: T. O. Oli Veera Karasenkova. Praegused eri nimekujud on viiside juures ja nimekirjas. Pole päris järjekindel 2-realisus. Kustutaksin helisalvetuse viite, sest salvestust ju ei ole. Teksti ehitus: ABRB, leidub lõppriimi.>', 1, 3158),
    ('EÜS IX 1333 (228)', NULL, 'ERA, Fon. 021 a', NULL, 'VI 858', 1, 1, 1, NULL, '<Kontrollitud: T. O. On teksti kogujad, aga pole teksti viidet. Kustutan siit kogujate nimed, sest ka tekstikogust ei leidnud - otsisin küll natuke pealiskaudselt.>', 1, 2219),
