    ('EÜS IX 568 (14)', 'EÜS IX 515 (12)', NULL, NULL, 'XIII 603', 1, 1, 1, NULL, '<Kontrollitud: T. O. Täpsustasin esitajat, andmebaasis on olnud kahtlus, kas Jaan Kelder või Ann Mäll. Kahtlus on tekkinud sellest, et ei ole teatud, mis number on esitaja järel lk 504. Arvestades, et esitajate nime järel on teksti number, on see Jaan Kelder. Parandasin viisi ja teksti koguja, kes olid läinud vahetusse.>', 1, 2021),
    ('EÜS IX 569 (18)', 'EÜS IX 527/8 (25)', NULL, NULL, 'XIII 598', 1, 1, 1, NULL, '<Kontrollitud: T. O. Parandasin esitaja, oli Mäll, Ann. Eksitus on tekkinud sellest, et esitaja järel olevat numbrit (andmed lk 504) on peetud viisi numbriks, aga nime järel on teksti number. Parandasin viisi ja teksti koguja, kes olid läinud vahetusse. 23.01.2021>', 1, 2011),
    ('EÜS IX 569 (18)', 'EÜS IX 528 (27)', NULL, NULL, 'XIII 598', 1, 1, 1, NULL, '<Kontrollitud: T. O. Parandasin esitaja, oli Mäll, Ann. Eksitus on tekkinud sellest, et esitaja järel olevat numbrit (andmed lk 504) on peetud viisi numbriks, aga nime järel on teksti number. Parandasin viisi ja teksti koguja, kes olid läinud vahetusse. Täpsustasin teksti viidet. 23.01.2021>', 1, 2012),
