    ('EÜS X 1030 (401)', 'N', 'ERA, Fon. 100 a', NULL, NULL, 1, 1, 1, NULL, '<Kontrollitud: T. O. 9 pos, vormist tegin AB, EÜS X 1030 (402) on sama viis kooriga, salvestust pole. Parandasin Kratsova - Krantsova. Määrasin rütmitüübi. 2.01.2021>', 1, 4209),
    ('EÜS X 1031 (403)', 'N', 'ERA, Fon. 100 b', NULL, NULL, 1, 1, 1, NULL, '<Kontrollitud: T. O Lisasilp, aga 8 pos, tõenäoliselt pika silbiga sõna tõttu, edaspidi aga tõenäoliselt tuleb 9 pos. Parandasin Kratsova - Krantsova. Määrasin rütmitüübi tavalises korras 2. 12.12.2020. Parandasin nüüd rütmitüübi vastavalt lisasilbi olemasolule, olles rohkem tegelenud setu lauludega. 2.01.2021>', 1, 4208),
    ('EÜS X 1042 (428)', 'N', NULL, NULL, 'VI 221', 1, 1, 1, NULL, NULL, NULL, 858),
    ('EÜS X 1038 (420)', 'N', NULL, NULL, NULL, 1, 1, 1, NULL, '<Kontrollitud: T. O 9 pos. Parandasin viite ja andmeid: oli EÜS X 1043 (430) ja samuti olid siin teise laulu EÜS X 1043 (430) esitaja andmed, mille parandasin. (Hulk jama.) Samad vead on Accessis. Ühesõnaga: Andmebaasis oli 2 viisi numbritega 4236 ja 4237, mõlema viide oli sama EÜS X 1043 (430). Esitaja järgi leidsin, et üks, nr 4236 peaks olema siinne EÜS X 1038 (420), aga kodeeritud viis nr 4236 ei vasta sellele. Ta kõlbab juhul, kui kodeerimisel on tehtud muutusi ja vigu: 9-positsioonilised read on muudetud 8-positsiooniliseks ja 4 nooti kodeeritud valesti. 12.12.2020 Määrasin nüüd rütmitüübi vastavalt lisasilbi olemasolule. 2.01.2021>', 1, NULL), 
    ('EÜS X 1043 (430)', 'N', 'ERA, Fon. 102 b', NULL, NULL, 1, 1, 1, NULL, '<Helisalvestus: Väga katkendlik, pole võimalik, et saaks uue ja parema noodistuse.>
    <Kontrollitud: T. O 9 pos. Parandasin andmeid. Accessis on number EÜS X 1043 (430) 2 korda - üks kord viis nr 4236 ja teinekord 4237, üldandmetes aga segamini siinse ja EÜS X 1038 (420) omad. Accessis on ilmselt ikka viga: seal on endiselt viis 4236, aga siinse viisi andmetega. 12.12.2020 Siinsele kirjele vastava viisi 4237 kodeeringus tundub viga - isegi kui taandada 9 pos-i 8-le, on 8. positsiooni noot vale. Määrasin nüüd rütmitüübi vastavalt lisasilbi olemasolule, olles rohkem tegelenud setu lauludega. 2.01.2021>', 1, 4237),
    ('EÜS X 1059 (458)', 'EÜS X 2061 (325)', 'ERA, Fon. 107 b', NULL, 'IX 327', 1, 1, 1, NULL, '<Helisalvestus: Arusaadav, tekst salvestusest pikem.>
    <Kontrollitud: T. O Lisasin teksti viite, tüübinime. T. O. 30.07.2020>', 1, 2734),
    ('EÜS X 1060 (462)', 'N', NULL, NULL, 'VI 233', 1, 1, 1, NULL, '<Kontrollitud: T. O. 30.07.2020>', 1, 885),
    ('EÜS X 1062 (465)', 'EÜS X 2072 (339)', 'ERA, Fon. 108 a', NULL, 'III 346', 1, 1, 1, NULL, '<Helisalvestus: Arusaadav.>
    <Kontrollitud: T. O. Lisasin teksti viite. Panin Kiigelaul asemele täpsema laulutüübi. T 30.07.2020. Rütmitüüp OK. 12.12.2020>', 1, 480),
    ('EÜS X 1062 (466)', 'EÜS X 2072 (340)', 'ERA, Fon. 108 b', NULL, 'XIII 338', 1, 1, 1, NULL, '<Helisalvestus: Arusaadav, tekst salvestusest pikem.>
    <Kontrollitud: T. O. Lisasin teksti viite. Panin rütmitüübi 9 nurksulgudesse, sest 1 ja 9 ei vaheldu korrapäraselt, rütmimuutused on pigem esituse variatsioonid. 30.07.2020>', 1, 1436),
