    ('EÜS X 1094 (530)', 'EÜS X 1094 (530)', NULL, NULL, 'III 58', 1, 1, 1, NULL, '<Helisalvestus: Siia juurde on kirjutatud helisalvestuse viide Fon 124 c (orig. 66) ja näeb välja nagu salvestuselt noodistatud, aga sellist salvestust ei ole, samade sõnadega algab teine viis teistsuguses esituses. Tegin tollele uue kirje.>
    <Kontrollitud: T. O. Pean originaalis siia juurde kirjutatud salvestust eksituseks (vt salvestuse märkust). Täpsustasin rütmitüüpi, oli 4. 30.07.2020>', 1, 4590),
    (NULL, NULL, 'ERA, Fon 124 c', NULL, NULL, 1, 1, 1, NULL, '<Helisalvestus: Selge, laulab üks inimene värsse kordamata>
    <Kontrollitud: T. O. Tegin uue kirje, sest sellest salvestusest ei ole noodistust. 1-realine viis. 30.07.2020>', 1, NULL), 
