    ('EÜS X 877 (50)', 'N', 'ERA, Fon. 064 a', NULL, NULL, 1, 1, 1, NULL, '<Kontrollitud: T. O 9 positsiooni: lisasilbiks on "noo". Registris on nimi Tepo. 30.07.2020>', 1, 4191),
    ('EÜS X 880 (57)', 'N', 'ERA, Fon. 065 c', NULL, NULL, 1, 1, 1, NULL, '<Kontrollitud: T. O 9 positsiooni: lisaks on "nu". 30.07.2020 Tegin rütmitüübi. 13.12.2020>', 1, 4190),
    ('EÜS X 880 (59)', 'N', 'ERA, Fon. 065 e', NULL, NULL, 1, 1, 1, NULL, '<Kontrollitud: T. O 9 positsiooni: lisasilbiks on "ks" või "nu". Kas see on ikka karjaselaul? 30.07.2020 Tegin rütmitüübi. 13.12.2020>', 1, 4189),
    ('EÜS X 883 (70)', 'N', NULL, NULL, NULL, 1, 1, 1, NULL, '<Kontrollitud: T. O 9 positsiooni: lisasilbiks on "no". Salvestust ei otsinud. Access andmebaasi võetud Setu kartoteegist. 30.07.2020>', 1, 4184),
    ('EÜS X 908 (121)', 'N', 'ERA, Fon. 072 f', NULL, NULL, 1, 1, 1, NULL, '<Kontrollitud: T. O 9 positsiooni. Andmebaasis oli enne esitajaks märgitud ?, Matrjona (Rodja Matr''o), (47, Karisilla>Tupluva), kes oli eelmise laulu eeslaulja. Originaalis on Väisäneni käega märgitud: ? Katti. Eelmistel lehtedel leidub laulja Teppo Katti. Väisänen nagu poleks isegi kindel. Salvestusel on kuulda, et laulja nr 121 hääl erineb eelmisest, nr 120 eeslaulja omast, seega minu meelest see pole Matrjona. Samas on Katti karajselaulu viisi EÜS X 911 (128) veidi teistsuguse viisiga. Mis ei tähenda, et ta poleks võinud mitut moodi laulda. Ka seal tuleb tema laul Matrjona järel. Siiski jäin praegu Katti juurde. Register pakub samuti esitajaks Rodja Matr''o, ilmselt on andmebaasi sisestata lähtunud registrist. Katti salvestus teise lauluga on Fon. 71 a, minu meelest see hääl langeb paremini kokku. Seega võib siin olla Katti või keegi muu laulja 13.12.2020>', 1, 4187),
    ('EÜS X 911 (128)', 'N', NULL, NULL, NULL, 1, 1, 1, NULL, '<Kontrollitud: T. O 9 positsiooni: lisasilbiks on "jo". Tegin rütmitüübi. 13.12.2020>', 1, 4188),
    ('EÜS X 925 (169)', 'N', 'ERA, Fon. 077 e', NULL, NULL, 1, 1, 1, NULL, '<Kontrollitud: T. O 9 positsiooni, lisasilpideks "nu" ja "meil". Stroofiks oli märgitud A, aga viisi all on 2 eri värssi. Muutsin ühtlustatud nimeks Taarka asemele Darja Pisumaa. 1856-1933. (Wiki) Kuulamisel on nootide pikendused veidi teisiti kui noodistuses. 13.12.2020>', 1, 4205),
    ('EÜS X 930 (180)', 'N', NULL, NULL, '363', 1, 1, 1, NULL, '<Kontrollitud: T. O. Ise nimetasin tüübi. See on 1-realine refrääniline viis, mida korratakse kooriga, koori killõ teistsugune. Tegin refräänilise rütmitüübi. 23.02.2021>', 1, 4122),
    ('EÜS X 939 (197)', 'N', NULL, NULL, NULL, 1, 1, 1, NULL, '<Kontrollitud: T. O. 1-realine viis, 9 pos. ja lisasilp.Rütmit määrasin 12.13.2020>', 1, 4212),
    ('EÜS X 939 (198)', 'EÜS X 939 (198)', NULL, NULL, NULL, 1, 1, 1, NULL, '<Kontrollitud: T. O. Pigem varieeruv 1-realine viis, lõpurida erinev, 9 pos. ja lisasilp. Rütmit määrasin 12.13.2020>', 1, 4213),
    ('EÜS X 951 (225)', 'N', NULL, NULL, NULL, 1, 1, 1, NULL, '<Kontrollitud: T. O. 8-silbilist värssi korratakse teise struktuuriga: lisatakse sõnakordus ja "nu." Ei saa aru, mida tähistab stroof A*.>', 1, 4178),
    ('EÜS X 956 (237)', 'N', NULL, NULL, NULL, 1, 1, 1, NULL, '<Kontrollitud: T. O.>', 1, 4176),
    ('EÜS X 963 (248)', 'N', 'ERA, Fon. 083 e', NULL, NULL, 1, 1, 1, NULL, '<Kontrollitud: T. O See meenutab refrääniga laulu, kus refrään on 1 viisirea pikkune. Selles mõttes on ta rangelt võttes 1-realine pika refrääniga viis. Panin ta siiski 2-realiseks, sest näide on lühike ja sarnane 2-realine laul on EÜS X 967 (259). Enne oli nimi Saska, Miku ühtlustatud ametlike nimede reas. Lisasin valla.>', 1, 888),
    ('EÜS X 967 (259)', 'EÜS X 967 (259)', 'ERA, Fon. 085 a', NULL, 'VI 297', 1, 1, 1, NULL, '<Kontrollitud: T. O Tõstsin teksti laulutüübis lahtrist välja ja lisasin tärni.>', 1, 903),
