    ('EÜS XI 873 (12b)', 'EÜS XI 908/9 (12)', 'ERA, Fon. 146 a', NULL, 'XI 438', 1, 1, 1, NULL, '<Kontrollitud: Kumbki noodistus (12a fonograafi järgi, 12b välitöödel) ei ole helisalvestusega võrreldes pisiasjades täpne. Arvatavasti on 12a jäämine viisikogus esitaja Madis Pillaparti''i alla eksitus, sest see on fonografeeringu noodistus ja salvestusel laulab naine. Siiski pole siin ilmselt 2 eri viisi, vaid ühe esituse kaks eri transkriptsiooni, mistõttu kustutasin teise kirje, oli ka viis nr 3347 ja kaart nr XI 437. Esitaja nimetäht n alakriipsuga tähistab selles kogus III väldet. T. O. 31.07.2020.>', 1, 3348),
    ('EÜS XI 875 (17)', 'EÜS XI 910/1 (14)', 'ERA, Fon. 146 c', NULL, 'IV 106', 1, 1, 1, NULL, '<Kontrollitud: T. O Helisalvestusel on rohkem värsse (8-10) kui noodi all, aga kvaliteet on jube, tekstikogus on ilmselt värsid vastavuses helisalvestusega.>', 1, 535),
    ('EÜS XI 888 (66)', 'EÜS XI 888 (66)', 'ERA, Fon. 157 a', NULL, '399', 1, 1, 1, NULL, '<Kontrollitud: T. O Riimiline või äärmisel juhul siirdevormiline laul: järjekindel anakruusiga värss ja 3/4 mõõdus viis. See, et viis on formaalselt 16 noodi pikkune, ei anna põhjust teda regiviisiks lugeda. Jätaksin välja. Seesama laul on EÜS XI 888 (65), Fon 14e - miks seda hulgas pole? Mõlemal on viide samale tekstile nr 8 - miks seda siia pole pandud?>', 1, 4129),
    ('EÜS XI 891 (81)', 'EÜS XI 945/6 (64)', 'ERA, Fon. 159 a', NULL, 'IV 103', 1, 1, 1, NULL, '<Kontrollitud: T. O Digiteeritud salvestust OHTOS pole. Vormile lisasin ka AA, sest kohati värssi korratakse, kohati mitte.>', 1, 534),
    ('EÜS XI 891 (83)', 'EÜS XI 947/8 (66)', 'ERA, Fon. 159 c', NULL, 'VIII 429', 1, 1, 1, NULL, '<Kontrollitud: T. O Digiteeritud salvestust OHTOS pole.>', 1, 2496),
    ('EÜS XI 891 (84)', 'EÜS XI 891 (84) / EÜS XI 950/2 (69)', 'ERA, Fon. 159 d', NULL, 'II 217', 1, 1, 1, NULL, '<Kontrollitud: T. O Digiteeritud salvestust OHTOS pole. Lisasin trad. tegevuse. Rütmitüüp vaadatud. 14.12.2020. T.O.>', 1, 370),
    ('EÜS XI 897 (96)', 'EÜS XI 962/3 (77)', 'ERA, Fon. 164 a', NULL, 'IV 412', 1, 1, 1, NULL, '<Kontrollitud: T. O Helisalvestusel on rohkem värsse (6) kui noodi all (2) . Parandasin vormi AA-ks AB-st, sest kordus on nii noodis kui helisalvestusel. Üsna imelik tekst. Lisasin siia trad. tegevuse.>', 1, 591),
    ('EÜS XI 897 (97)', 'EÜS XI 963/4 (78)', 'ERA, Fon. 164 b', NULL, 'IV 84', 1, 1, 1, NULL, '<Kontrollitud: T. O Helisalvestusel on sama tekst, mis selle noodi all, kuid rohkem värsse (6) kui noodi all (4). Salvestusel kordab laulik kõiki värsse., seetõttu lisasin vormile AA. Noodis ei ole kordamist märgitud. Viisi juures on viide neljale tekstile. Lisasin tüübinime ja trad. tegevuse.>', 1, 525),
    ('EÜS XI 897 (97)', 'EÜS XI 964/7 (79)', 'ERA, Fon. 164 b', NULL, 'IV 84', 1, 1, 1, NULL, '<Helisalvestus: noodist erinev tekst>
