    ('RKM II 57, 15 (2)', 'RKM II 57, 15/7 (2)', NULL, NULL, NULL, 1, 1, 1, '<Vissel, Anu 1982. Eesti karjaselaulud 1. Setu karjaselaulud>', '<Kontrollitud: T. O. Tavaliselt on rohkem kui 8-positsioonilised värsid: on lisasilp ja värsi korduv algussõna, 8-12 silpi. Väga täpne noodistus mõne värsi kohta, nagu oleks helisalvestuse transkriptsioon; palju värsse aga noodistamata. Lisasin teksti viite. Rütmitüüp on kahtlane, tegin 17.12.2020 ja 4.01.2021>', 1, 4152),
    ('RKM II 57, 257 (29)', 'RKM II 57, 257/8 (29)', NULL, NULL, 'VI 999', 1, 1, 1, '<Salve, Krsiti, Sarv, Vaike 1987. Setu lauludega muinasjutud>', '<Kontrollitud: T. O. Lisasin teksti viite.>', 1, 2245),
