    ('RKM II 57, 329 (1)', 'RKM II 57, 329/31 (1)', NULL, NULL, NULL, 1, 1, 1, '<Vissel, Anu 1982. Eesti karjaselaulud 1. Setu karjaselaulud>', '<Kontrollitud: T. O. Tavaliselt on rohkem kui 8silbilised värsid: koos lisasilpidega 9 või 10 positsiooni.>', 1, 4202),
