    ('RKM III 2, 130', NULL, 'ERA, Pl. 10 B2', NULL, 'IV 117', 1, 1, 1, NULL, '<Kontrollitud: T. O. Parandasin küla nime Wiki järgi: andmebaasis oli Paksa, orig. Posksa. Rütmitüüp ka kontrollitud. 1.01.2021>', 1, 540),
    ('RKM III 3, 100 (35)', NULL, NULL, NULL, 'XII 232', 1, 1, 1, NULL, '<Kontrollitud: T. O. Parandasin küla nime Wiki järgi: andmebaasis oli Paksa, orig. Posksa. Lisasin rütmitüübi. 1.01.2021>', 1, 4348),
    ('RKM III 3, 100 (36)', 'RKM II 62, 156 (36)', NULL, NULL, NULL, 1, 1, 1, NULL, '<Kontrollitud: T. O. 9-positsiooniline värss. Parandasin küla nime Wiki järgi: andmebaasis oli Paksa, orig. Posksa. Täpsustasin rütmitüüpi, oli 1. 1.01.2021>', 1, 4235),
    ('RKM III 3, 100 (37)', NULL, NULL, NULL, 'XII 231', 1, 1, 1, NULL, '<Kontrollitud: T. O. 9-positsiooniline värss. Parandasin küla nime Wiki järgi: andmebaasis oli Paksa, orig. Posksa. Rütmitüüp ka kontrollitud. 1.01.2021>', 1, 4347),
    ('RKM III 3, 100 (38)', NULL, NULL, NULL, '382', 1, 1, 1, NULL, '<Kontrollitud: T. O. Parandasin küla nime Wiki järgi: andmebaasis oli Paksa, orig. Posksa. Rütmitüüp ka kontrollitud. 1.01.2021>', 1, 4124),
    ('RKM III 3, 100 (40)', 'RKM II 62, 162/4 (40)', NULL, NULL, NULL, 1, 1, 1, NULL, '<Kontrollitud: T. O. Parandasin viisi viite, oli RKM III 3, 100 (4), Osalt 9-positsioonilised read.>', 1, 4223),
    ('RKM III 3, 101 (43)', 'RKM II 62, 163 (43)', NULL, NULL, NULL, 1, 1, 1, NULL, '<Kontrollitud: T. O. 9-positsiooniline värss. Lisasin rütmitüübi, esitaja andmeid. 1.01.2021>', 1, 4234),
    ('RKM III 3, 107 (70)', NULL, NULL, NULL, 'XV 504', 1, 1, 1, NULL, '<Kontrollitud: T. O. Võib olla 4-realine viis, sest koguja on tavaliselt noodistanud ühe läbilaulu. Kihelkonna märkisin Rõuge, kuigi Ruusmäe kuulumise osas on suur ajalooline segadus. Enne oli siin: Oli: Vastseliina?=Rõuge? Ise nimetasin laulutüübi. Rütmitüüpi täpsustasin, oli 1. 1.01.2021>', 1, 3962),
    ('RKM III 3, 108 (75)', NULL, NULL, NULL, 'XI 175', 1, 1, 1, NULL, '<Kontrollitud: T. O. Kihelkonna märkisin Rõuge, kuigi Ruusmäe kuulumise osas on suur ajalooline segadus. Oli: Vastseliina?=Rõuge? Parandasin stroofi, täpsustasin rütmitüüpi, oli 1. 1.01.2021>', 1, 3146),
    ('RKM III 3, 110 (82)', NULL, NULL, NULL, '329', 1, 1, 1, NULL, '<Kontrollitud: T. O. See on 1-realine refrääniline laul, ei kuulu siia. Kihelkonna märkisin Rõuge, kuigi Ruusmäe kuulumise osas on suur ajalooline segadus. Oli: Vastseliina?=Rõuge? Muutsin rütmitüübi lihtsalt refrääniliseks. 1.01.2021>', 1, 4044),
    ('RKM III 3, 110 (86)', 'RKM II 62, 241/2 (1)', NULL, NULL, NULL, 1, 1, 1, NULL, '<Kontrollitud: T. O. Parandasin viisi viite, oli RKM II 3, 110 (86). Määrasin rütmitüübi. 5.01.2021>', 1, 4239),
    ('RKM III 3, 111 (88)', NULL, NULL, NULL, 'XI 186', 1, 1, 1, NULL, '<Kontrollitud: T. O. Laulja juures originaalis elukohta ei näe, andmebaasis oli märgitud samuti nagu eelmine kirje, RKM III 3, 108 (75). Oli: Vastseliina?=Rõuge? Ma jätsin praegu nii ja panin Rõuge khk, nagu ka eelmise puhul. Rütmitüüp OK. 1.01.2021>', 1, 3153),
    ('RKM III 3, 114 (108)', NULL, NULL, NULL, NULL, 1, 1, 1, NULL, '<Kontrollitud: T. O. 9-positsiooniline värss. Lisasin rütmitüübi. 1.01.2021>', 1, 4206),
    ('RKM III 3, 114 (109)', 'RKM II 62, 292/6 (1)', NULL, NULL, NULL, 1, 1, 1, NULL, '<Kontrollitud: T. O. 9-positsiooniline ja pikem värss; muutub asukoht ja silbiarv. Määrasin segase ja muutuva rütmitüübi. 1.01.2021>', 1, 4207),
    ('RKM III 3, 126 (169)', NULL, NULL, NULL, 'X 205', 1, 1, 1, NULL, '<Kontrollitud: Rütmitüüp OK. 1.01.2021>', NULL, 2951),
    (NULL, NULL, 'ERA, Fon. 515 b', NULL, 'V 189', 1, 1, 1, NULL, '<Kontrollitud: T. O. Noodistatud on helisalvestuse järgi. Parandasin viisi viite, oli RKM III 3, 134/8. Rütmitüüp OK. Üle kuulamata. 1.01.2021>', 1, 870),
    (NULL, NULL, 'ERA, Fon. 517 a', NULL, 'XII 309', 1, 1, 1, NULL, '<Kontrollitud: T. O. Noodistatud on helisalvestuse järgi. Lisasin salvestuse viite (seda ei ole transkriptsiooni juures), stroofi. Rütmitüüp OK. Üle kuulamata. 1.01.2021>', 1, 4385),
    (NULL, NULL, 'ERA, Fon. 518 b', NULL, 'VI 251', 1, 1, 1, NULL, '<Kontrollitud: T. O. Noodistatud on helisalvestuse järgi. Salvestuse viidet ei ole transkriptsiooni juures. Rütmitüüpi täpsustasin, oli 3. Üle kuulamata. 1.01.2021>', 1, 1068),
    (NULL, NULL, 'ERA, Fon. 519 b', NULL, 'I 867', 1, 1, 1, NULL, '<Kontrollitud: T. O. Noodistatud on helisalvestuse järgi. Salvestuse viidet ei ole transkriptsiooni juures. Rütmitüüp OK. Üle kuulamata. 1.01.2021>', 1, 324),
    (NULL, NULL, 'ERA, Fon. 519 c', NULL, 'I 708', 1, 1, 1, NULL, '<Kontrollitud: T. O. Noodistatud on helisalvestuse järgi, salvestuse viidet ei ole transkriptsiooni juures. Rütmitüüp OK. Samast viisist oli andmebaasis topelt kirje, teine vigase viitega RKM III 3, 142 (69), kuid sama salvestuse viitega Fon. 519 c; sellel oli viisi number 318. Kustutasin selle teise kirje. Rütmitüüp oli seal määratud 4A. Kuulasin üle, rütmis ei ole muud erilist kui silbijaotused. 1. ja 5.01.2021>', 1, 4556),
    (NULL, 'ERA II 268', 'ERA, Fon. 526 c', NULL, 'VI 897', 1, 1, 1, NULL, '<Kontrollitud: T. O. Teksti tuleb veel otsida. Noodistatud on helisalvestuse järgi. Salvestuse viidet ei ole transkriptsiooni juures. Rütmitüüpi muutsin, oli 1. Panin algul 4G [4H2, 4H3], aga siis lihtsustasin. Üle kuulamata. 1.01.2021, 11-01.2021>', 1, 2242),
    ('RKM III 3, 51 (25)', 'N', NULL, NULL, 'II 608', 1, 1, 1, NULL, '<Kontrollitud: T. O. Parandasin viisikoguja, oli Tampere. Muutsin rütmitüüpi, oli 7. Peab vaatama, ehk rütmitüüp 7 kasutusele võtta... sest 5 on väga suureks paisunud. 1.01.2021>', 1, 4583),
    ('RKM III 3, 53 (29)', 'RKM III 3, 53 (29)', NULL, NULL, 'XI 68', 1, 1, 1, NULL, '<Kontrollitud: T. O. Rütmitüüp OK. Üle kuulamata. 2.01.2021>', 1, 3104),
    ('RKM III 3, 54 (32)', 'RKM II 48, 291 (1)', NULL, NULL, 'X 85', 1, 1, 1, '<VK XI, lk 390/1>', '<Kontrollitud: Lisasin teksti viite. Samast laulust samalt esitajalt on veel variante. T. O. 31.07.2020>', 1, 2872),
    ('RKM III 3, 54 (32)', 'RKM II 48, 373 (1)', NULL, NULL, NULL, 1, 1, 1, '<VK XI, lk 390/1>', '<Kontrollitud: Lisasin teksti viite ja tegin uue kirje. Samast laulust samalt esitajalt on veel variante. T. O. 31.07.2020>', 1, 2872),
